import logging
from dataclasses import dataclass
from typing import Dict, List
import unittest

# Configure logging for production visibility
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class InventoryError(Exception):
    """Base exception for inventory domain errors."""
    pass

@dataclass
class InventoryItem:
    """Data model representing an item in the inventory."""
    name: str
    quantity: int

    def __post_init__(self):
        if self.quantity < 0:
            raise InventoryError(f"Quantity for {self.name} cannot be negative.")

class InventoryManager:
    """Manages inventory operations with validation and low-stock alerts."""

    LOW_STOCK_THRESHOLD = 5

    def __init__(self) -> None:
        self._inventory: Dict[str, InventoryItem] = {}

    def add_item(self, name: str, initial_quantity: int) -> None:
        """Adds a new item to the inventory."""
        if name in self._inventory:
            raise InventoryError(f"Item '{name}' already exists.")
        self._inventory[name] = InventoryItem(name, initial_quantity)
        logger.info(f"Added item: {name} with quantity {initial_quantity}")

    def update_stock(self, name: str, delta: int) -> None:
        """Updates stock levels and triggers alerts if below threshold."""
        if name not in self._inventory:
            raise InventoryError(f"Item '{name}' not found in inventory.")

        item = self._inventory[name]
        new_quantity = item.quantity + delta

        if new_quantity < 0:
            raise InventoryError(f"Insufficient stock for '{name}'. Current: {item.quantity}, Requested delta: {delta}")

        item.quantity = new_quantity

        if item.quantity < self.LOW_STOCK_THRESHOLD:
            logger.warning(f"ALERT: Low stock for '{name}'. Current quantity: {item.quantity}")

    def get_low_stock_items(self) -> List[str]:
        """Returns a list of item names currently below the threshold."""
        return [name for name, item in self._inventory.items() if item.quantity < self.LOW_STOCK_THRESHOLD]

class TestInventoryManager(unittest.TestCase):
    """Unit tests for InventoryManager."""

    def setUp(self) -> None:
        self.mgr = InventoryManager()
        self.mgr.add_item("Widget", 10)

    def test_add_item_success(self) -> None:
        self.mgr.add_item("Gadget", 5)
        self.assertEqual(self.mgr._inventory["Gadget"].quantity, 5)

    def test_add_duplicate_item_raises_error(self) -> None:
        with self.assertRaises(InventoryError):
            self.mgr.add_item("Widget", 5)

    def test_update_stock_success(self) -> None:
        self.mgr.update_stock("Widget", -2)
        self.assertEqual(self.mgr._inventory["Widget"].quantity, 8)

    def test_insufficient_stock_raises_error(self) -> None:
        with self.assertRaises(InventoryError):
            self.mgr.update_stock("Widget", -15)

    def test_low_stock_alert_trigger(self) -> None:
        self.mgr.update_stock("Widget", -6)
        self.assertIn("Widget", self.mgr.get_low_stock_items())

if __name__ == "__main__":
    unittest.main()
